import { useEffect, useState } from 'react';
import axios from 'axios';
import TurfCard from '../components/TurfCard';
import SportFilter from '../components/SportFilter';

const API = 'http://localhost:5000/api';

export default function Explore() {
  const [turfs, setTurfs] = useState([]);
  const [sport, setSport] = useState('All');
  const [search, setSearch] = useState('');
  const [maxPrice, setMaxPrice] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get(`${API}/turfs`)
      .then(res => { setTurfs(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const filtered = turfs.filter(t => {
    const matchSport = sport === 'All' || t.sport === sport;
    const matchSearch = t.name.toLowerCase().includes(search.toLowerCase()) ||
      t.location.toLowerCase().includes(search.toLowerCase());
    const matchPrice = maxPrice ? t.price_per_hour <= parseInt(maxPrice) : true;
    return matchSport && matchSearch && matchPrice;
  });

  return (
    <div style={{ padding: '2rem', maxWidth: '1200px', margin: '0 auto' }}>
      <h2 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>Explore Turfs</h2>
      <p style={{ color: '#666', marginBottom: '1.5rem' }}>Find and book the perfect turf near you</p>
      <div style={{
        display: 'flex', gap: '1rem', flexWrap: 'wrap',
        background: 'white', padding: '1rem',
        borderRadius: '12px', border: '1px solid #eee',
        marginBottom: '1.5rem',
        boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
      }}>
        <input
          placeholder="🔍 Search by name or location..."
          value={search}
          onChange={e => setSearch(e.target.value)}
          style={{
            flex: 1, padding: '10px 14px', borderRadius: '10px',
            border: '1px solid #ddd', fontSize: '0.95rem', minWidth: '200px',
          }}
        />
        <input
          placeholder="Max Price (₹/hr)"
          type="number"
          value={maxPrice}
          onChange={e => setMaxPrice(e.target.value)}
          style={{
            width: '160px', padding: '10px 14px', borderRadius: '10px',
            border: '1px solid #ddd', fontSize: '0.95rem',
          }}
        />
      </div>
      <SportFilter selected={sport} onSelect={setSport} />
      {loading ? (
        <p style={{ color: '#666', textAlign: 'center', marginTop: '3rem' }}>Loading turfs...</p>
      ) : filtered.length === 0 ? (
        <p style={{ color: '#666', textAlign: 'center', marginTop: '3rem' }}>No turfs found. Try different filters.</p>
      ) : (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
          gap: '1.5rem', marginTop: '1rem',
        }}>
          {filtered.map(turf => <TurfCard key={turf.id} turf={turf} />)}
        </div>
      )}
    </div>
  );
}
